# BETTER: Guard clauses to reduce nesting
print("\nBETTER: Guard clauses:")
def process_order_good(order, user, inventory):
    if not user.is_authenticated:
        print("User not authenticated")
        return False

    if not user.has_permission("order"):
        print("No permission to order")
        return False

    if not order.items:
        print("Empty order")
        return False

    if not all(item.in_stock for item in order.items):
        print("Some items out of stock")
        return False

    if user.balance < order.total:
        print("Insufficient balance")
        return False

    # Process order
    print("Processing order...")
    for item in order.items:
        if item.quantity <= 0:
            print(f"Invalid quantity for {item.name}")
            return False
        inventory.update(item)

    print("Order successful!")
    return True

