print("\nForm validation:")
def validate_form(data):
    errors = []

    # Check each field
    if not data.get("username"):
        errors.append("Username required")
    elif len(data["username"]) < 3:
        errors.append("Username too short")
    elif len(data["username"]) > 20:
        errors.append("Username too long")

    if not data.get("email"):
        errors.append("Email required")
    elif "@" not in data["email"]:
        errors.append("Invalid email")

    if not data.get("password"):
        errors.append("Password required")
    elif len(data["password"]) < 8:
        errors.append("Password too short")

    # Check passwords match (nested inside password check)
    if data.get("password") and data.get("confirm_password"):
        if data["password"] != data["confirm_password"]:
            errors.append("Passwords don't match")

    return errors if errors else "Validation passed"

test_data = {
    "username": "jo",
    "email": "invalid",
    "password": "pass123",
    "confirm_password": "pass456"
}
print(f"Validation result: {validate_form(test_data)}")

