# Creating nested dictionaries
company = {
    "name": "Tech Corp",
    "departments": {
        "engineering": {
            "manager": "Alice",
            "employees": ["Bob", "Charlie", "Diana"],
            "budget": 500000
        },
        "marketing": {
            "manager": "Eve",
            "employees": ["Frank", "Grace"],
            "budget": 200000
        },
        "sales": {
            "manager": "Henry",
            "employees": ["Ivy", "Jack", "Kevin"],
            "budget": 300000
        }
    },
    "location": {
        "address": "123 Main St",
        "city": "San Francisco",
        "zip": "94105"
    }
}

print(f"Company: {company['name']}")
print(f"Engineering manager: {company['departments']['engineering']['manager']}")
print(f"Marketing employees: {company['departments']['marketing']['employees']}")

# Accessing nested values safely
print(f"\nSafe access:")

# Method 1: Chained get() with default
eng_budget = company.get('departments', {}).get('engineering', {}).get('budget')
print(f"Engineering budget: {eng_budget}")

# Method 2: try-except
try:
    hr_budget = company['departments']['hr']['budget']
except KeyError:
    print("HR department not found")

# Method 3: Helper function
def get_nested(d, *keys, default=None):
    for key in keys:
        try:
            d = d[key]
        except (KeyError, TypeError):
            return default
    return d

hr_budget = get_nested(company, 'departments', 'hr', 'budget', default=0)
print(f"HR budget with helper: {hr_budget}")

# Adding nested values
print(f"\nAdding nested values:")
if 'hr' not in company['departments']:
    company['departments']['hr'] = {}
company['departments']['hr']['manager'] = "Lucy"
company['departments']['hr']['employees'] = ["Mike", "Nina"]
company['departments']['hr']['budget'] = 150000
print(f"HR added: {company['departments']['hr']}")

# Updating nested values
company['departments']['engineering']['budget'] = 600000
print(f"Updated engineering budget: {company['departments']['engineering']['budget']}")

# Iterating through nested dictionaries
print(f"\nDepartment budgets:")
for dept, data in company['departments'].items():
    print(f"{dept}: ${data.get('budget', 0)}")

# List all employees across departments
print(f"\nAll employees:")
all_employees = []
for dept, data in company['departments'].items():
    all_employees.extend(data.get('employees', []))
print(all_employees)

# Nested dictionary from lists
print(f"\nBuilding nested dict from lists:")
keys1 = ["A", "B"]
keys2 = ["X", "Y"]
values = [[1, 2], [3, 4]]

# Method 1: Nested loops
nested1 = {}
for i, k1 in enumerate(keys1):
    nested1[k1] = {}
    for j, k2 in enumerate(keys2):
        nested1[k1][k2] = values[i][j]
print(f"Built with loops: {nested1}")

# Method 2: Nested comprehension
nested2 = {k1: {k2: values[i][j] for j, k2 in enumerate(keys2)} for i, k1 in enumerate(keys1)}
print(f"Built with comprehension: {nested2}")

# Deep copy vs shallow copy
print(f"\nCopying nested dicts:")
original = {"a": 1, "b": {"c": 2, "d": [3, 4]}}
shallow = original.copy()
deep = copy.deepcopy(original)

original["b"]["c"] = 99
original["b"]["d"].append(5)

print(f"Original: {original}")
print(f"Shallow copy affected: {shallow}")
print(f"Deep copy unaffected: {deep}")

# Flatten nested dictionary
print(f"\nFlatten nested dict:")
nested = {
    "a": 1,
    "b": {
        "c": 2,
        "d": {
            "e": 3,
            "f": 4
        }
    },
    "g": 5
}

def flatten_dict(d, parent_key='', sep='.'):
    items = []
    for k, v in d.items():
        new_key = f"{parent_key}{sep}{k}" if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep=sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

flattened = flatten_dict(nested)
print(f"Flattened: {flattened}")

# Unflatten back
def unflatten_dict(d, sep='.'):
    result = {}
    for key, value in d.items():
        parts = key.split(sep)
        current = result
        for part in parts[:-1]:
            if part not in current:
                current[part] = {}
            current = current[part]
        current[parts[-1]] = value
    return result

unflattened = unflatten_dict(flattened)
print(f"Unflattened: {unflattened}")

# Nested dictionary with defaultdict
from collections import defaultdict

# Automatic nested creation
nested_dd = defaultdict(lambda: defaultdict(dict))
nested_dd['user']['profile']['name'] = "Alice"
nested_dd['user']['profile']['age'] = 30
nested_dd['user']['settings']['theme'] = "dark"
print(f"\nWith defaultdict: {dict(nested_dd)}")

# Practical example: Configuration files
config = {
    "database": {
        "host": "localhost",
        "port": 5432,
        "name": "mydb",
        "credentials": {
            "username": "admin",
            "password": "secret"
        }
    },
    "logging": {
        "level": "INFO",
        "file": "/var/log/app.log",
        "format": "json"
    }
}

# Access configuration
db_host = get_nested(config, 'database', 'host')
db_port = get_nested(config, 'database', 'port')
print(f"\nDatabase config: {db_host}:{db_port}")

# Merge nested configurations
def merge_dicts(d1, d2):
    """Deep merge two dictionaries."""
    result = d1.copy()
    for key, value in d2.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key] = merge_dicts(result[key], value)
        else:
            result[key] = value
    return result

default_config = {
    "database": {
        "host": "localhost",
        "port": 5432,
        "pool_size": 10
    },
    "logging": {
        "level": "WARNING"
    }
}

user_config = {
    "database": {
        "host": "db.example.com",
        "pool_size": 20
    },
    "debug": True
}

merged = merge_dicts(default_config, user_config)
print(f"\nMerged config: {merged}")

